-- This code is generated by AI, edited by humans

-- Portable Authorization — reference implementation extensions
-- Tier 2 X.509 metadata and stateful/cumulative authorization counters.

BEGIN;

-- ── Tier 2 X.509 trust metadata ────────────────────────────────────
ALTER TABLE portauth_trusted_issuers
  ADD COLUMN IF NOT EXISTS x509_subject TEXT,
  ADD COLUMN IF NOT EXISTS x509_san_uri TEXT,
  ADD COLUMN IF NOT EXISTS x509_trust_anchor_pem TEXT,
  ADD COLUMN IF NOT EXISTS x509_trust_anchor_sha256 TEXT,
  ADD COLUMN IF NOT EXISTS x509_revocation_policy TEXT NOT NULL DEFAULT 'soft-fail'
    CHECK (x509_revocation_policy IN ('soft-fail', 'hard-fail'));

CREATE TABLE IF NOT EXISTS portauth_x509_revoked_certificates (
  fingerprint_sha256 TEXT PRIMARY KEY,
  issuer_id          TEXT,
  reason             TEXT,
  active             BOOLEAN NOT NULL DEFAULT TRUE,
  revoked_at         TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_portauth_x509_revoked_issuer
  ON portauth_x509_revoked_certificates (issuer_id);

-- Allow the issuer store to persist certificate-backed JWT credentials.
ALTER TABLE portauth_issued_credentials
  DROP CONSTRAINT IF EXISTS portauth_issued_credentials_format_check;

ALTER TABLE portauth_issued_credentials
  ADD CONSTRAINT portauth_issued_credentials_format_check
  CHECK (format IN ('jwt', 'vc-jose', 'x509-jwt'));

-- ── Stateful/cumulative authorization profile ──────────────────────
CREATE TABLE IF NOT EXISTS portauth_authorization_counters (
  counter_key     TEXT PRIMARY KEY,
  credential_id   TEXT,
  agent_id        TEXT,
  issuer_id       TEXT,
  constraint_type TEXT NOT NULL,
  window_start    TIMESTAMPTZ NOT NULL,
  window_end      TIMESTAMPTZ NOT NULL,
  used_amount     NUMERIC(38, 6) NOT NULL DEFAULT 0,
  usage_count     BIGINT NOT NULL DEFAULT 0,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at      TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_portauth_authorization_counters_agent
  ON portauth_authorization_counters (agent_id);

CREATE INDEX IF NOT EXISTS idx_portauth_authorization_counters_window
  ON portauth_authorization_counters (window_end);

CREATE TABLE IF NOT EXISTS portauth_authorization_counter_events (
  idempotency_key  TEXT NOT NULL,
  counter_key      TEXT NOT NULL REFERENCES portauth_authorization_counters(counter_key),
  credential_id    TEXT,
  increment_amount NUMERIC(38, 6) NOT NULL DEFAULT 0,
  recorded_at      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  PRIMARY KEY (idempotency_key, counter_key)
);

COMMIT;
